/**
 * Add inner HTML to this element. The supplied HTML will be parsed, and each node appended to the end of the children.
 * @param html HTML to add inside this element, after the existing HTML
 * @return this element
 * @see #html(String)
 */
public Element append(String html) {
    Validate.notNull(html);

    Element fragment = Parser.parseBodyFragment(html, baseUri).body();
    for (Node node : fragment.childNodes()) {
        node.parentNode = null;

        // Special handling for table elements
        if (this.tag.getName().equals("table") && node instanceof Element) {
            String nodeName = ((Element) node).tagName();
            if ("tr".equalsIgnoreCase(nodeName)) {
                // For table rows, find or create a tbody to contain them
                Element tbody = null;
                // Look for existing tbody, thead, or tfoot to append to
                for (Node child : childNodes) {
                    if (child instanceof Element) {
                        String childName = ((Element) child).tagName();
                        if ("tbody".equalsIgnoreCase(childName) || 
                            "thead".equalsIgnoreCase(childName) || 
                            "tfoot".equalsIgnoreCase(childName)) {
                            tbody = (Element) child;
                            // We'll add to the last one found to maintain order
                        }
                    }
                }

                // If no tbody/thead/tfoot exists, create a tbody for the row
                if (tbody == null) {
                    tbody = new Element(Tag.valueOf("tbody"), baseUri());
                    appendChild(tbody);
                }

                // Add the row to the tbody instead of directly to table
                tbody.appendChild(node);
            } else {
                // For other elements, add directly
                appendChild(node);
            }
        } else {
            // For non-table contexts, add directly
            appendChild(node);
        }
    }
    return this;
}

